build.gradle.kts<pre><code>plugins {
    `maven-publish`
    kotlin("jvm") version "2.3.20" // (1)!
    id("hytale-mod") version "0.+" 
}

group = "com.example"
version = "0.1.0"
val javaVersion = 25

dependencies {
    compileOnly(libs.jetbrains.annotations)
    compileOnly(libs.jspecify)
}

hytale { // (2)!
    // uncomment if you want to add the Assets.zip file to your external libraries;
    // ⚠️ CAUTION, this file is very big and might make your IDE unresponsive for some time!
    //
    // addAssetsDependency = true

    // uncomment if you want to develop your mod against the pre-release version of the game.
    //
    // updateChannel = "pre-release"
}

kotlin {
    jvmToolchain(javaVersion) // (3)!
}

java {
    withSourcesJar()
}

// .. rest of your settings.gradle.kts
</code></pre> <ol> <li>Add kotlin plugin into your plugins block. At the time of writing this guide, latest stable version of Kotlin is <code>2.30.20</code>. The rest of the plugins are Plugin specific.</li> <li>This is configuration for <code>hytale-mod</code> plugin, if you don't use it, then you don't need to have it. </li> <li>This is configuration for kotlin compiler, it tells it to compile to the same java version as the rest of the project. Hytale Server uses Java 25, so this should be set to <code>25</code> Look line <code>:9</code></li> </ol>

build.gradle.kts<pre><code>dependencies {
    // ... your other dependencies
    implementation("io.github.dawidprosba:hytale-aergia-mod-devkit:0.0.2")
    ksp("io.github.dawidprosba:hytale-aergia-mod-devkit:0.0.2")
}
</code></pre>
